// Find B2B contacts where next email is due
const result = $input.first().json;
const contacts = result.results || [];
const now = new Date();
const toProcess = [];

for (const c of contacts) {
  const props = c.properties || {};
  const etape = parseInt(props.sequence_b2b_etape || '0');
  const nextDate = props.sequence_b2b_date_debut ? new Date(props.sequence_b2b_date_debut) : null;

  // Only process if next step date is in the past
  if (nextDate && nextDate <= now && etape < 5) {
    toProcess.push({ json: {
      contactId: c.id,
      email: props.email || '',
      prenom: props.firstname || 'Madame/Monsieur',
      nom: props.lastname || '',
      societe: props.company || '',
      etape: etape
    }});
  }
}

if (toProcess.length === 0) return [];
return toProcess;

// Calculate next step date
const contact = $('Code JS - Filtrer contacts B2B').item.json;
const etape = contact.etape;
const delays = [0, 3, 7, 14, 30];

// Next step delay (days)
const nextEtape = etape + 1;
const nextDelay = nextEtape < delays.length ? delays[nextEtape] - delays[etape] : null;
const nextDate = nextDelay !== null ? new Date(Date.now() + nextDelay * 24 * 3600 * 1000).toISOString() : null;

return [{ json: {
  contactId: contact.contactId,
  newEtape: nextEtape,
  nextDate: nextDate,
  isLastStep: nextEtape >= 5
}}];
